import React, { useState, useEffect } from 'react';
import * as XLSX from 'xlsx';
import './App.css';
import Header from './components/Header';
import Sidebar from './components/Sidebar';
import Table from './components/Table';
import CartPanel from './components/CartPanel';
import Toast from './components/Toast';
import DropZone from './components/DropZone';
import DEFAULT_DATA from './data/defaultData.json';

function App() {
  const [data, setData] = useState(DEFAULT_DATA);
  const [filtered, setFiltered] = useState([]);
  const [cart, setCart] = useState([]);
  const [search, setSearch] = useState('');
  const [filters, setFilters] = useState({ regions: [], categories: [], nccs: [] });
  const [cartOpen, setCartOpen] = useState(false);
  const [toast, setToast] = useState('');
  const [fileName, setFileName] = useState('');
  const [currentPage, setCurrentPage] = useState(1);

  const PAGE_SIZE = 30;

  // Load from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('nvl_vpp_data');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setData(parsed);
      } catch (e) {
        console.error('Failed to load saved data:', e);
      }
    }
  }, []);

  // Save to localStorage whenever data changes
  useEffect(() => {
    if (data.length > 0) {
      localStorage.setItem('nvl_vpp_data', JSON.stringify(data));
    }
  }, [data]);

  // Apply filters
  useEffect(() => {
    let result = data;

    if (filters.regions.length > 0) {
      result = result.filter(d => filters.regions.includes(d.vc));
    }
    if (filters.categories.length > 0) {
      result = result.filter(d => filters.categories.includes(d.cat));
    }
    if (filters.nccs.length > 0) {
      result = result.filter(d => filters.nccs.includes(d.ncc));
    }

    if (search.trim()) {
      const q = search.toLowerCase().trim();
      const words = q.split(/\s+/);
      result = result.filter(d => {
        const text = `${d.sp} ${d.ncc} ${d.cat} ${d.mon} ${d.tv}`.toLowerCase();
        return words.every(w => text.includes(w));
      });
    }

    setFiltered(result);
    setCurrentPage(1);
  }, [data, search, filters]);

  const handleFileUpload = (file) => {
    setFileName(file.name);
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const wb = XLSX.read(e.target.result, { type: 'array' });
        const sheetName = wb.SheetNames.find(s => s.toLowerCase().includes('master')) || wb.SheetNames[0];
        const ws = wb.Sheets[sheetName];
        const rows = XLSX.utils.sheet_to_json(ws, { defval: '' });

        const newData = rows
          .map(r => {
            const get = (...keys) => {
              for (let k of keys) {
                for (let col of Object.keys(r)) {
                  const colNorm = col.toLowerCase().replace(/\s+/g, '');
                  const kNorm = k.toLowerCase().replace(/\s+/g, '');
                  if (colNorm.includes(kNorm) || kNorm.includes(colNorm)) {
                    return String(r[col] || '').trim();
                  }
                }
              }
              return '';
            };

            return {
              vc: get('Vùng Code', 'VùngCode'),
              tv: get('Tên Vùng', 'TênVùng'),
              ncc: get('NCC'),
              sp: get('Tên sản phẩm', 'Tênsảnphẩm'),
              dvt: get('Đơn vị tính', 'Đơnvịtính'),
              cat: get('Category'),
              mac: get('Material Area Code', 'MaterialAreaCode'),
              man: get('Material Area Name', 'MaterialAreaName'),
              mgc: get('Material Group Code', 'MaterialGroupCode'),
              mgn: get('Material Group Name', 'MaterialGroupName'),
              moc: get('Material Object Code', 'MaterialObjectCode', 'MOC'),
              mon: get('Material Object Name', 'MaterialObjectName'),
              price: parseFloat(get('PRICE PER UNIT', 'PricePerUnit', 'Đơn giá')) || 0,
            };
          })
          .filter(r => r.sp);

        setData(newData);
        showToast(`✅ Đã tải ${newData.length} sản phẩm từ ${file.name}`);
      } catch (err) {
        showToast(`❌ Lỗi đọc file: ${err.message}`);
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const showToast = (msg) => {
    setToast(msg);
    setTimeout(() => setToast(''), 2500);
  };

  const toggleFilter = (type, value) => {
    setFilters(prev => {
      const arr = [...prev[type]];
      const idx = arr.indexOf(value);
      if (idx >= 0) {
        arr.splice(idx, 1);
      } else {
        arr.push(value);
      }
      return { ...prev, [type]: arr };
    });
  };

  const clearFilters = () => {
    setSearch('');
    setFilters({ regions: [], categories: [], nccs: [] });
  };

  const addToCart = (item) => {
    const existing = cart.findIndex(
      c => c.sp === item.sp && c.vc === item.vc && c.ncc === item.ncc
    );
    if (existing >= 0) {
      const newCart = [...cart];
      newCart.splice(existing, 1);
      setCart(newCart);
      showToast(`🗑 Đã xóa: ${item.sp}`);
    } else {
      setCart([...cart, { ...item, qty: 1 }]);
      showToast(`✅ Đã thêm: ${item.sp}`);
    }
  };

  const removeFromCart = (idx) => {
    const newCart = [...cart];
    const name = newCart[idx].sp;
    newCart.splice(idx, 1);
    setCart(newCart);
    showToast(`🗑 Đã xóa: ${name}`);
  };

  const updateQty = (idx, qty) => {
    const newCart = [...cart];
    newCart[idx].qty = Math.max(1, parseInt(qty) || 1);
    setCart(newCart);
  };

  const clearCart = () => {
    setCart([]);
    showToast('🗑 Đã xóa tất cả');
  };

  const exportCart = () => {
    if (cart.length === 0) {
      showToast('⚠️ Chưa có sản phẩm để xuất');
      return;
    }

    const today = new Date();
    const dateStr = today.toLocaleDateString('vi-VN');

    const headers = [
      'STT', 'Ngày', 'Tên Vùng', 'NCC', 'Tên sản phẩm', 'Đơn vị tính',
      'Quy cách', 'Số Lượng', 'Đơn giá (VND)', 'VAT', 'Tổng tiền', 'Category', 'Material Object'
    ];

    const data = cart.map((c, i) => [
      i + 1,
      dateStr,
      c.tv,
      c.ncc,
      c.sp,
      c.dvt,
      '',
      c.qty,
      c.price || '',
      c.price > 0 ? 0.08 : '',
      c.price > 0 ? c.price * c.qty * 1.08 : '',
      c.cat,
      `${c.moc} - ${c.mon}`,
    ]);

    const ws = XLSX.utils.aoa_to_sheet([headers, ...data]);
    ws['!cols'] = [
      { wch: 5 }, { wch: 12 }, { wch: 14 }, { wch: 40 },
      { wch: 30 }, { wch: 12 }, { wch: 10 }, { wch: 10 },
      { wch: 14 }, { wch: 6 }, { wch: 16 }, { wch: 18 }, { wch: 24 }
    ];

    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Đề xuất mua hàng');

    const fileName = `De_xuat_mua_hang_${today.getFullYear()}${String(today.getMonth() + 1).padStart(2, '0')}${String(today.getDate()).padStart(2, '0')}.xlsx`;
    XLSX.writeFile(wb, fileName);
    showToast(`📥 Đã xuất: ${fileName}`);
  };

  const regions = [...new Set(data.map(d => d.vc).filter(Boolean))].sort();
  const categories = [...new Set(data.map(d => d.cat).filter(Boolean))].sort();
  const nccs = [...new Set(data.map(d => d.ncc).filter(Boolean))].sort();

  return (
    <div className="app">
      <Header data={data} onFileSelect={handleFileUpload} />

      <div className="main">
        <Sidebar
          search={search}
          onSearchChange={setSearch}
          filters={filters}
          onToggleFilter={toggleFilter}
          onClearFilters={clearFilters}
          regions={regions}
          categories={categories}
          nccs={nccs}
          hasData={data.length > 0}
        />

        <div className="content">
          {data.length === 0 ? (
            <DropZone onFileSelect={handleFileUpload} fileName={fileName} />
          ) : null}

          {data.length > 0 && (
            <Table
              filtered={filtered}
              cart={cart}
              onAddToCart={addToCart}
              currentPage={currentPage}
              onPageChange={setCurrentPage}
              pageSize={PAGE_SIZE}
            />
          )}
        </div>
      </div>

      {data.length > 0 && (
        <>
          <button
            className="cart-fab"
            onClick={() => setCartOpen(true)}
          >
            🛒
            {cart.length > 0 && <span className="fab-badge">{cart.length}</span>}
          </button>

          <CartPanel
            isOpen={cartOpen}
            onClose={() => setCartOpen(false)}
            cart={cart}
            onRemove={removeFromCart}
            onUpdateQty={updateQty}
            onClear={clearCart}
            onExport={exportCart}
          />
        </>
      )}

      <Toast message={toast} />
    </div>
  );
}

export default App;
